// Gelişmiş Parmak İzi
const SECURITY_ID = btoa(navigator.platform + screen.colorDepth).slice(0, 15);
const ADMIN_SECRET = "data:image/png;base64,"; // Bunu kimseyle paylaşma!

// F12 ve Debugger Tuzağı
setInterval(() => {
    const startTime = performance.now();
    debugger; 
    if (performance.now() - startTime > 100) {
        window.location.href = "about:blank"; // F12 açanı boş sayfaya atar
    }
}, 500);

// Admin Kontrolü (Sadece senin tarayıcında çalışır)
function isOverlord() {
    return localStorage.getItem('access_token') === ADMIN_SECRET;
}

// Sağ tık ve tuş engelleme
document.addEventListener('contextmenu', e => e.preventDefault());
document.onkeydown = e => {
    if (e.keyCode == 123 || (e.ctrlKey && e.shiftKey && (e.keyCode == 73 || e.keyCode == 74))) return false;
};
